 1	import type { FC } from 'react';
 2	
 3	import { VirtualizedTable } from '@openshift-console/dynamic-plugin-sdk';
 4	import { Stack, StackItem } from '@patternfly/react-core';
 5	
 6	import { affinityColumns } from './utils/constants';
 7	import type { AffinityRowData } from './utils/types';
 8	import AddAffinityRuleButton from './AddAffinityRuleButton';
 9	import AffinityDescriptionText from './AffinityDescriptionText';
10	import AffinityRow from './AffinityRow';
11	
12	type AffinityListProps = {
13	  affinities: AffinityRowData[];
14	  onAffinityClickAdd: () => void;
15	  onDelete: (affinity: AffinityRowData) => void;
16	  onEdit: (affinity: AffinityRowData) => void;
17	};
18	
19	const AffinityList: FC<AffinityListProps> = ({
20	  affinities,
21	  onAffinityClickAdd,
22	  onDelete,
23	  onEdit,
24	}) => {
25	  const columns = affinityColumns();
26	  return (
27	    <Stack hasGutter>
28	      <StackItem>
29	        <AffinityDescriptionText />
30	      </StackItem>
31	      <StackItem data-testid="affinity-rules-list">
32	        <VirtualizedTable<AffinityRowData>
33	          columns={columns}
34	          data={affinities ?? []}
35	          loaded
36	          loadError={false}
37	          Row={AffinityRow}
38	          rowData={{ onDelete, onEdit }}
39	          unfilteredData={affinities || []}
40	        />
41	      </StackItem>
42	      <StackItem>
43	        <AddAffinityRuleButton isLinkButton onAffinityClickAdd={onAffinityClickAdd} />
44	      </StackItem>
45	    </Stack>
46	  );
47	};
48	export default AffinityList;

